#include <bits/stdc++.h>
using namespace std;
int main(){
    int a,b;a=b=0;
    char c[10],y;bool flag=true;
    cin>>c;
    for(int i=0;i<strlen(c);i++){
        if(c[i]>='0' && c[i]<='9' && flag)a=a*10+c[i]-'0';
        else if(c[i]>='0' && c[i]<='9' && !flag)b=b*10+c[i]-'0';
        else if(c[i]==' ')flag=false;
        else{
        	flag=false;
        	y=c[i];
		}
    }
    if(y=='+')cout<<a+b;
    else if(y=='-')cout<<a-b;
    else if(y=='*')cout<<a*b;
    else if(y=='/')cout<<a/b;
    else cout<<a%b;
    return 0;
}
